import { Sudoku } from './sudoku';

// 注释掉 Store 引用，防止在测试环境下因别名问题报错
// 如果 UI 需要使用，建议在 UI 组件内直接引用 Store
export class Game {
  constructor() {
    this.sudoku = new Sudoku(); 
    this.history = [];
    this.isPaused = false;
  }

  // 契约测试必填
  getSudoku() {
    return this.sudoku;
  }

  // 契约测试必填：直接代理填数逻辑
  guess(row, col, value) {
    if (this.isPaused) return;
    this.makeMove(row, col, value);
  }

  startNew(diff) {
    this.sudoku = Sudoku.generate(diff);
    this.history = [];
    this.isPaused = false;
    // UI 相关的 timer.start() 等逻辑建议放在调用它的 Svelte 组件里
  }

  makeMove(row, col, value) {
    if (this.isPaused) return;
    this.history.push(this.sudoku.clone());
    this.sudoku.guess(row, col, value);
  }

  undo() {
    if (this.history.length > 0) {
      this.sudoku = this.history.pop();
    }
  }

  pause() {
    this.isPaused = true;
  }

  resume() {
    this.isPaused = false;
  }
}

// 导出类用于测试，导出实例用于 UI
export const gameInstance = new Game();
export default gameInstance;
